        ctx = c.get('context', [])
        if ctx:
            print(f'  Context ({len(ctx)} messages):')
            for i, m in enumerate(ctx):
                print(f'    [{i}] {m[\"role\"]}: {m[\"text\"][:100]}')
        seed = c.get('workspace_seed', [])
        if seed:
            print(f'  Workspace seed:')
            for s in seed:
                print(f'    - {json.dumps(s)}')
        print()
"

