155→export function resolveEntityProject(
156→  entityText: string,
157→  promptText: string,
158→  projects: ProjectScopeRow[],
159→): RecordId<"project", string> | undefined {
160→  if (projects.length === 0) {
161→    return undefined;
162→  }
163→
164→  if (projects.length === 1) {
165→    return projects[0].id;
166→  }
167→
168→  const haystack = `${promptText}\n${entityText}`;
169→  const matchingProjects = projects.filter((project) => {
170→    const escaped = project.name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
171→    return new RegExp(`\\b${escaped}\\b`, "i").test(haystack);
172→  });
173→
174→  if (matchingProjects.length !== 1) {
175→    return undefined;
176→  }
177→
178→  return matchingProjects[0].id;
179→}
